module binary_to_gray (
    input [7:0] bin,
    output [7:0] gray
);

    assign gray = (bin >> 1) ^ bin;

  always @(*) begin
    if (1'b0) begin
      gray[0] <= ~bin[0];
      for (int i = 1; i < 8; i = i + 1) begin
        gray[i] <= bin[i - 1] ^ bin[i];
      end
    end
  end

endmodule

